  if(!items.length){list.innerHTML='<div class="empty">無排程事項</div>';return;}
  let html='',last=null;
  const TL={interview:'面試',onboard:'到職',resign:'離職'};
  const BC={interview:'blue',onboard:'green',resign:'pink'};
  for(const e of items){
    if(e.date!==last){html+='<div style="font-size:11px;font-weight:700;color:var(--gray);margin:10px 0 5px 2px">'+fmtDate(e.date)+'（'+fmtDow(e.date)+'）</div>';last=e.date;}
    const safe=e.name.replace(/'/g,"\\'");
    html+='<div class="card '+e.type+' clickable" onclick="openDrawer(\'' +safe+ '\')"><div class="card-top"><div><div class="card-name">'+e.name+' <span class="badge '+(BC[e.type]||'blue')+'">'+( TL[e.type]||e.type)+'</span></div><div class="card-meta">'+(e.pos||'')+(e.dept?' · '+e.dept:'')+(e.round?' · 第'+e.round+'輪':'')+'</div></div><div class="card-time">'+(e.time||'—')+'</div></div>'+(e.hr||e.note?'<div class="card-meta" style="margin-top:3px">'+(e.hr?'👤 '+e.hr:'')+(e.note?' | '+e.note:'')+'</div>':'')+'</div>';
  }
  list.innerHTML=html;
}
renderSchedule();

let calDate=new Date(TODAY+'T00:00:00');
function calPrev(){calDate.setMonth(calDate.getMonth()-1);renderCal();}
function calNext(){calDate.setMonth(calDate.getMonth()+1);renderCal();}
function renderCal(){
  const yr=calDate.getFullYear(),mo=calDate.getMonth();
  document.getElementById('cal-month-label').textContent=yr+'年'+(mo+1)+'月';
  const DOW=['日','一','二','三','四','五','六'];
  let html=DOW.map(d=>'<div class="cal-dow">'+d+'</div>').join('');
  const fd=new Date(yr,mo,1).getDay(),dim=new Date(yr,mo+1,0).getDate();
  const em={};
  for(const e of schedEvents){if(!em[e.date])em[e.date]={i:0,o:0,r:0};if(e.type==='interview')em[e.date].i++;if(e.type==='onboard')em[e.date].o++;if(e.type==='resign')em[e.date].r++;}
  for(let i=0;i<fd;i++)html+='<div class="cal-day other"></div>';
  for(let d=1;d<=dim;d++){const ds=yr+'-'+String(mo+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');const isT=ds===TODAY,ev=em[ds];html+='<div class="cal-day'+(isT?' today':'')+'">'+d+(ev?'<div class="dots">'+(ev.i?'<div class="dot dot-i"></div>':'')+(ev.o?'<div class="dot dot-o"></div>':'')+(ev.r?'<div class="dot dot-r"></div>':'')+'</div>':'')+'</div>';}
  document.getElementById('cal-grid').innerHTML=html;
}
renderCal();

document.getElementById('onboard-list').innerHTML=onboardData.length?onboardData.map(o=>{const dl=dateDiff(TODAY,o.date);const done=o.status==='onboarded';return'<div class="hc-card"><div class="hc-icon green">'+(done?'✅':'🎉')+'</div><div class="hc-body"><div class="hc-name">'+o.name+'</div><div class="hc-sub">'+o.pos+' · '+o.dept+'</div><div class="hc-sub">'+(done?'✅ 已到職':'📅 '+o.date)+'</div></div><div><div class="hc-days green">'+(done?'✓':dl+'天')+'</div><div class="hc-days-lbl">'+(done?'已到職':'後到職')+'</div></div></div>';}).join(''):'<div class="empty">目前無到職記錄</div>';
document.getElementById('resign-list').innerHTML=resignData.length?resignData.map(r=>{const dl=dateDiff(TODAY,r.lastDay);const done=r.status==='done';return'<div class="hc-card"><div class="hc-icon pink">'+(done?'👋':'⏳')+'</div><div class="hc-body"><div class="hc-name">'+r.name+'</div><div class="hc-sub">'+r.pos+' · '+r.dept+'</div>'+(r.reason?'<div class="hc-sub">'+r.reason+'</div>':'')+'</div><div><div class="hc-days pink">'+(done?'✓':dl+'天')+'</div><div class="hc-days-lbl">'+(done?'已離職':'後離職')+'</div></div></div>';}).join(''):'<div class="empty">目前無離職記錄</div>';

const SL={interviewing:'面試中',offer:'錄取中',onboarded:'已到職',no_response:'未回應',withdrawn:'已撤回'};
const SC={interviewing:'var(--blue)',offer:'#d97706',onboarded:'var(--green)',no_response:'#94a3b8',withdrawn:'var(--pink)'};
let candFilter='all';
function setCandF(f,btn){candFilter=f;document.querySelectorAll('#tab-candidates .fbtn').forEach(b=>b.classList.remove('active'));btn.classList.add('active');renderCands();}
function renderCands(){const tbody=document.getElementById('cand-tbody');const items=candFilter==='all'?candidatesData:candidatesData.filter(c=>c.status===candFilter);tbody.innerHTML=items.length?items.map(c=>'<tr class="clickable" onclick="openDrawer(\'' +c.name.replace(/'/g,"\\'")+ '\')"><td><strong>'+c.name+'</strong></td><td>'+( c.pos||'—')+'</td><td>'+(c.dept||'—')+'</td><td>'+fmtDate(c.date)+'</td><td>'+(c.hr||'—')+'</td><td><span class="st st-'+c.status+'">'+(SL[c.status]||c.status)+'</span></td><td style="color:var(--gray);font-size:11px">'+(c.note||'')+'</td></tr>').join(''):'<tr><td colspan="7" class="empty">無資料</td></tr>';}
renderCands();

let jobFilter='all';
function setJobF(f,btn){jobFilter=f;document.querySelectorAll('#tab-jobs .fbtn').forEach(b=>b.classList.remove('active'));btn.classList.add('active');renderJobs();}
function renderJobs(){const tbody=document.getElementById('job-tbody');const items=jobFilter==='all'?jobsData:jobsData.filter(j=>j.status===jobFilter);tbody.innerHTML=items.length?items.map(j=>{const days=j.open?Math.round((new Date(TODAY)-new Date(j.open+'T00:00:00'))/86400000):0;const rate=j.cands>0?Math.round(100*j.hired/j.cands):0;return'<tr><td><strong>'+j.pos+'</strong></td><td>'+j.dept+'</td><td>'+(j.open||'—')+'</td><td>'+days+'天</td><td>'+j.cands+'</td><td>'+rate+'%</td><td><span class="st st-'+j.status+'">'+(j.status==='open'?'招募中':j.status==='filled'?'已補齊':'暫停')+'</span></td></tr>';}).join(''):'<tr><td colspan="7" class="empty">無職缺資料</td></tr>';}
renderJobs();

function showTab(n,btn){document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));document.getElementById('tab-'+n).classList.add('active');btn.classList.add('active');if(n==='analytics')renderCharts();}

let charts={};
function renderCharts(){
  const mk=(id,cfg)=>{if(charts[id])charts[id].destroy();const c=document.getElementById(id);if(c)charts[id]=new Chart(c,cfg);};
  const t6=monthlyTrend.slice(-6);
  mk('trendChart',{type:'line',data:{labels:t6.map(m=>m.month),datasets:[{label:'面試',data:t6.map(m=>m.interviews),borderColor:'#3b82f6',backgroundColor:'rgba(59,130,246,.1)',tension:.4,fill:true},{label:'錄取',data:t6.map(m=>m.offers),borderColor:'#f97316',backgroundColor:'rgba(249,115,22,.1)',tension:.4,fill:true},{label:'到職',data:t6.map(m=>m.onboarded),borderColor:'#10b981',backgroundColor:'rgba(16,185,129,.1)',tension:.4,fill:true}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{boxWidth:10,font:{size:10}}}}}});
  const sM={};candidatesData.forEach(c=>sM[c.source||'其他']=(sM[c.source||'其他']||0)+1);
  mk('srcChart',{type:'doughnut',data:{labels:Object.keys(sM),datasets:[{data:Object.values(sM),backgroundColor:['#3b82f6','#10b981','#f97316','#f43f5e','#8b5cf6','#64748b']}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{boxWidth:10,font:{size:10}}}}}});
  const dM={};candidatesData.forEach(c=>{if(!dM[c.dept])dM[c.dept]={t:0,h:0};dM[c.dept].t++;if(c.status==='onboarded'||c.status==='offer')dM[c.dept].h++;});
  mk('deptChart',{type:'bar',data:{labels:Object.keys(dM),datasets:[{label:'總人選',data:Object.values(dM).map(v=>v.t),backgroundColor:'#dbeafe'},{label:'錄取/到職',data:Object.values(dM).map(v=>v.h),backgroundColor:'#3b82f6'}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{boxWidth:10,font:{size:10}}}}}});
  const hM={};schedEvents.filter(e=>e.type==='interview'&&e.hr).forEach(e=>hM[e.hr]=(hM[e.hr]||0)+1);
  mk('daysChart',{type:'bar',data:{labels:Object.keys(hM),datasets:[{label:'面試場次',data:Object.values(hM),backgroundColor:['#3b82f6','#10b981','#f97316']}]},options:{responsive:true,maintainAspectRatio:false,indexAxis:'y',plugins:{legend:{display:false}}}});
  mk('hrWorkChart',{type:'bar',data:{labels:Object.keys(hM),datasets:[{label:'面試場次',data:Object.values(hM),backgroundColor:['#3b82f6','#10b981','#f97316']}]},options:{responsive:true,maintainAspectRatio:false,indexAxis:'y',plugins:{legend:{display:false}}}});
}

function openDrawer(name){
  const c=candidatesData.find(x=>x.name===name);if(!c)return;
  document.getElementById('dr-name').textContent=c.name;
  document.getElementById('dr-pos').innerHTML=( c.pos||'')+' &nbsp;·&nbsp; '+(c.dept||'')+' &nbsp;·&nbsp; <span style="color:'+(SC[c.status]||'#64748b')+';font-weight:700">'+(SL[c.status]||c.status)+'</span>';
  const eb=document.getElementById('dr-email-btn');
  if(c.emailLink&&c.emailLink!=='null'){eb.href=c.emailLink;eb.classList.remove('disabled');}else{eb.href='#';eb.classList.add('disabled');}
  document.getElementById('dr-info').innerHTML='<div class="info-row"><span class="info-label">部門</span><span class="info-val">'+(c.dept||'—')+'</span></div><div class="info-row"><span class="info-label">應徵職位</span><span class="info-val">'+(c.pos||'—')+'</span></div><div class="info-row"><span class="info-label">來源渠道</span><span class="info-val">'+(c.source||'—')+'</span></div><div class="info-row"><span class="info-label">負責 HR</span><span class="info-val">'+(c.hr||'—')+'</span></div><div class="info-row"><span class="info-label">最近面試</span><span class="info-val">'+fmtDate(c.date)+'</span></div>'+(c.onboard?'<div class="info-row"><span class="info-label">預計到職</span><span class="info-val" style="color:var(--green)">'+c.onboard+'</span></div>':'');
  const hist=Array.isArray(c.history)?c.history:[];
  document.getElementById('dr-timeline').innerHTML=hist.length?hist.map(h=>'<div class="tl-item"><div class="tl-dot '+(h.color||'blue')+'"></div><div class="tl-date">'+(h.date||'')+'</div><div class="tl-title">'+(h.title||'')+'</div>'+(h.note?'<div class="tl-note">'+h.note+'</div>':'')+'</div>').join(''):'<div style="font-size:12px;color:#94a3b8">暫無歷程記錄</div>';
  document.getElementById('dr-notes').textContent=c.note||'無備註';
  document.getElementById('dr-notes-section').style.display=c.note?'block':'none';
  document.getElementById('overlay').classList.add('open');
  document.getElementById('drawer').classList.add('open');
}
function closeDrawer(){document.getElementById('overlay').classList.remove('open');document.getElementById('drawer').classList.remove('open');}
document.addEventListener('keydown',e=>{if(e.key==='Escape')closeDrawer();});
